const WebSocket = require('ws');

const ws = new WebSocket('ws://127.0.0.1:37249/', {
  headers: {
    'Authorization': 'Bearer 51748841efb6483a638b07d7d96d61678bd8619b7cbb8e86'
  }
});

ws.on('open', () => {
  console.log('Connected to gateway');

  // Try to list sessions
  const msg = {
    jsonrpc: '2.0',
    method: 'sessions.list',
    params: {},
    id: 1
  };
  ws.send(JSON.stringify(msg));
});

ws.on('message', (data) => {
  console.log('Received:', data.toString());
  ws.close();
});

ws.on('error', (err) => {
  console.error('Error:', err.message);
});
EOF
