import WebSocket from 'ws';

const gatewayUrl = 'ws://127.0.0.1:37249';
const token = '51748841efb6483a638b07d7d96d61678bd8619b7cbb8e86';
const targetSessionKey = 'agent:002:main';

const message = `002，听到请回复。

请读取 /root/.openclaw-002/workspace/pipeline/brief.md，然后写大纲到 /root/.openclaw-002/workspace/pipeline/outline.md。

选题：iPhone 17 Pro 本地跑 400B 大模型——端侧 AI 时代来了。

特别强调：文章必须有一个普通人不查资料也能用的干货（比如"当前能用的端侧AI应用清单"或"手机跑大模型的3种方式对比"），纯新闻介绍不过。

结尾必须加钩子（读取 /root/.openclaw-002/workspace/templates/wechat-hook.md，原封不动复制到文章末尾）。

写完大纲后用 sessions_send 通知我（001）。`;

const ws = new WebSocket(gatewayUrl, {
  headers: {
    'Authorization': `Bearer ${token}`
  }
});

let requestId = 1;

function sendRPC(method, params) {
  const msg = {
    jsonrpc: '2.0',
    method: method,
    params: params,
    id: requestId++
  };
  ws.send(JSON.stringify(msg));
}

ws.on('open', () => {
  console.log('Connected to gateway');

  // Try to send a message to agent:002:main
  sendRPC('sessions.send', {
    key: targetSessionKey,
    message: message
  });
  console.log('Sent message to', targetSessionKey);
});

ws.on('message', (data) => {
  const response = JSON.parse(data.toString());
  console.log('Received response:', JSON.stringify(response, null, 2));

  if (response.id && response.id < requestId) {
    ws.close();
    process.exit(0);
  }
});

ws.on('error', (err) => {
  console.error('WebSocket error:', err.message);
  process.exit(1);
});

ws.on('close', () => {
  console.log('Connection closed');
  process.exit(0);
});

// Timeout after 10 seconds
setTimeout(() => {
  console.log('Timeout - no response received');
  ws.close();
  process.exit(1);
}, 10000);
EOF

